	if len(badFields) > 0 {
		return handlers.InvalidArgumentErrorf("Error in provided request.", badFields)
	}

	return nil
}"}, {"name_path": "validateUpdateRequest", "kind": "Function", "relative_path": "internal/daemon/controller/handlers/credentials/credential_service.go", "body_location": {"start_line": 695, "end_line": 750}, "body": "func validateUpdateRequest(req *pbs.UpdateCredentialRequest) error {
